                                        <div class="mud-picker-stick-outer mud-hour" data-stick-value="@((_i + 12) % 24)"></div>
                                    </div>
                                }
                            }
                        </div>
                        <div class="@MinuteDialClassname">   
                            @*Minutes from 05 to 60 (00) - step 5*@                     
                            @for (int i = 0; i < 12; ++i)
                            {
                                var _i = i;
