                                <MudText Class="@GetNumberColor(_i * 5)" Style="@GetTransform(angle, 109, 0, 5)">@((_i * 5).ToString("D2"))</MudText>
                            }
                            @for (int i = 0; i < 60; ++i)
                            {
                                var _i = i;
                                <div class="mud-picker-stick mud-minute" style="@($"transform: rotateZ({_i * 6}deg);")" data-stick-value="@_i"></div>
                            }
                        </div>
                    </div>
                </div>
            </div>
        </MudPickerContent>
    </CascadingValue>;
}

@namespace MudBlazor
@using MudBlazor.Interfaces
@typeparam T
@inherits MudFormComponent<T, T>

@{
#pragma warning disable CS0618 // Type or member is obsolete
}

<MudInputControl Class="@Classname" Style="@Style" Error="@HasErrors" ErrorText="@GetErrorText()" Required="@Required">
    <InputContent>
        <CascadingValue Value="@((IMudRadioGroup)this)" IsFixed="false">
            @* Form should be cascaded as null so the childs are not registered to the Form *@
            <CascadingValue TValue="IForm" Value="null">
                <CascadingValue TValue="bool" Name="ParentDisabled" Value="@GetDisabledState()">
                    <CascadingValue TValue="bool" Name="ParentReadOnly" Value="@GetReadOnlyState()">
                        <div role="radiogroup" @attributes="UserAttributes" class="@GetInputClass()" style="@InputStyle" required="@Required" aria-required="@Required.ToString().ToLowerInvariant()">
                            @ChildContent
                        </div>
                    </CascadingValue>
                </CascadingValue>
            </CascadingValue>
        </CascadingValue>
    </InputContent>
</MudInputControl>

