    [TestFixture]
    public class AriaRoleCleanupTests : BunitTest
    {
        [Test]
        public void MudSlider_ShouldNotHaveRoleSliderOrManualAriaValues()
        {
            var comp = Context.Render<MudSlider<double>>(x =>
            {
                x.Add(p => p.Min, 100.0);
                x.Add(p => p.Max, 200.0);
                x.Add(p => p.Value, 120.0);
            });

            var input = comp.Find(".mud-slider-input");

            // Should be a native range input - no explicit role needed
            input.HasAttribute("role").Should().BeFalse();

            // Native range input should NOT have manual aria-valuenow/valuemin/valuemax
            // The browser provides these from native semantics
            input.HasAttribute("aria-valuenow").Should().BeFalse();
            input.HasAttribute("aria-valuemin").Should().BeFalse();
            input.HasAttribute("aria-valuemax").Should().BeFalse();

            // But native min/max/step attributes should still exist
            input.GetAttribute("min").Should().Be("100");
            input.GetAttribute("max").Should().Be("200");
            input.GetAttribute("step").Should().Be("1");
        }

        [Test]
        public void MudRadio_ShouldNotHaveRoleRadio()
        {
            var comp = Context.Render<MudRadio<bool>>();

            var input = comp.Find("input[type=\"radio\"]");

            // Should be a native radio input - no explicit role needed
            input.HasAttribute("role").Should().BeFalse();

            // Native radio input should NOT have aria-disabled
            // The native disabled attribute conveys this semantics
            input.HasAttribute("aria-disabled").Should().BeFalse();
        }

        [Test]
        public async Task MudRadioGroup_ShouldNotHavePlainRequiredAttributeOnDiv()
        {
            var comp = Context.Render<RadioGroupRequiredTest>();

            // The radiogroup div should NOT have plain 'required' attribute (invalid for div)
            comp.Find("div[role=\"radiogroup\"]").HasAttribute("required").Should().BeFalse();

            // But aria-required should still be present
            comp.Find("div[role=\"radiogroup\"]").GetAttribute("aria-required").Should().Be("false");

            // Even when Required=true, the div should not have plain required
            await comp.SetParametersAndRenderAsync(parameters => parameters
                .Add(p => p.Required, true));

            comp.Find("div[role=\"radiogroup\"]").HasAttribute("required").Should().BeFalse();
            comp.Find("div[role=\"radiogroup\"]").GetAttribute("aria-required").Should().Be("true");
        }

        [Test]
        public void MudTimePicker_ClockFaceShouldNotHaveMenuRole()
        {
            var comp = Context.Render<MudTimePicker>();

            // Open the picker
            comp.Find(".mud-picker-input").Click();

            // Wait for the picker to open
            comp.WaitForAssertion(() =>
            {
                var clockMask = comp.Find(".mud-picker-time-clock-mask");
                clockMask.HasAttribute("role").Should().BeFalse();
            });
        }
    }
}

